/**
 * AuthProvider — Provides authentication context to the entire application tree.
 * In production, replace the mock with MSAL PublicClientApplication.
 * @security Tokens stored in sessionStorage (cleared on tab close).
 */
import React, { createContext, useContext, useState, useCallback } from 'react';
import { User, UserRole } from '@shared/types';

export interface AuthContextType {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  login: () => Promise<void>;
  logout: () => void;
  getAccessToken: () => Promise<string | null>;
}

const AuthContext = createContext<AuthContextType | null>(null);

// Generated by GitHub Copilot
/** Mock user for development — replace with MSAL in production */
const MOCK_USER: User = {
  id: 'usr-001',
  displayName: 'Jane Doe',
  email: 'jane.doe@partner-portal.com',
  role: UserRole.Admin,
  avatarUrl: undefined,
};

const MOCK_TOKEN = 'mock-jwt-token-for-development';

/**
 * AuthProvider wraps the app tree and provides auth state.
 * @accessibility No direct UI — provides context only.
 */
export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(MOCK_USER);
  const [isLoading, setIsLoading] = useState(false);

  const login = useCallback(async () => {
    setIsLoading(true);
    try {
      // TODO: Replace with MSAL loginPopup / loginRedirect
      // const msalInstance = new PublicClientApplication(msalConfig);
      // const response = await msalInstance.loginPopup({ scopes: ['User.Read'] });
      setUser(MOCK_USER);
      sessionStorage.setItem('auth_token', MOCK_TOKEN);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const logout = useCallback(() => {
    setUser(null);
    sessionStorage.removeItem('auth_token');
    // TODO: msalInstance.logoutRedirect();
  }, []);

  const getAccessToken = useCallback(async (): Promise<string | null> => {
    // TODO: Replace with msalInstance.acquireTokenSilent
    return sessionStorage.getItem('auth_token');
  }, []);

  const value: AuthContextType = {
    user,
    isAuthenticated: !!user,
    isLoading,
    login,
    logout,
    getAccessToken,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

/**
 * Hook to access auth context from any component.
 * @throws Error if used outside AuthProvider.
 */
export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};
